import{_ as t,o,c as a,a0 as s}from"./chunks/framework.BU6BaNeX.js";const g=JSON.parse('{"title":"What is geoplot-themes?","description":"An introduction to geoplot-themes, a Python package that acts as a bridge to render stunning maps using ggplot2.","frontmatter":{"title":"What is geoplot-themes?","description":"An introduction to geoplot-themes, a Python package that acts as a bridge to render stunning maps using ggplot2."},"headers":[],"relativePath":"guide/what-is-geoplot-themes.md","filePath":"guide/what-is-geoplot-themes.md"}'),i={name:"guide/what-is-geoplot-themes.md"};function n(r,e,l,d,c,h){return o(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="what-is-geoplot-themes" tabindex="-1">What is geoplot-themes? <a class="header-anchor" href="#what-is-geoplot-themes" aria-label="Permalink to &quot;What is geoplot-themes?&quot;">​</a></h1><p><strong><code>geoplot-themes</code></strong> is a Python package designed for geospatial data scientists and cartographers who demand publication-quality, aesthetically stunning maps without sacrificing the power of the Python data science ecosystem.</p><p>While Python tools like <code>geopandas</code> and <code>matplotlib</code> are incredibly powerful for data processing and basic plotting, they often lack the declarative elegance, cartographic precision, and beautiful defaults of R&#39;s <code>ggplot2</code>.</p><p><code>geoplot-themes</code> solves this by acting as a bridge: you process your spatial data in Python, but render it using a customized <code>ggplot2</code> engine under the hood.</p><h2 id="why-use-geoplot-themes" tabindex="-1">Why use geoplot-themes? <a class="header-anchor" href="#why-use-geoplot-themes" aria-label="Permalink to &quot;Why use geoplot-themes?&quot;">​</a></h2><ol><li><strong>Cartographic Precision</strong>: Automatically generated scale bars, north arrows, and properly aligned legends.</li><li><strong>Infinite Overlays</strong>: Stack multiple vector layers on top of raster data, each with completely independent color and fill scales (thanks to <code>ggnewscale</code>).</li><li><strong>No More Aspect Ratio Nightmares</strong>: Automatically resolves orientation and aspect ratio so your maps are never stretched or padded with ugly white borders.</li><li><strong>Beautiful Themes</strong>: Stop tweaking <code>matplotlib</code> rcParams. Use hand-crafted, publication-ready themes out of the box.</li></ol>',6)])])}const m=t(i,[["render",n]]);export{g as __pageData,m as default};
